it = iter(sys.stdin.read().split())
n = int(next(it))
nums = [int(next(it)) for _ in range(n)]
count = {}
for num in nums:
    if num in count:
        count[num] += 1
    else:
        count[num] = 1
for num, freq in count.items():
    if freq > n / 2:
        print(num)

