#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin >> n;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    unordered_map<int, int> count;
    for(int num : nums){
        count[num]++;
    }
    for(auto& pair : count){
        if(pair.second > n / 2){
            cout << pair.first << endl;
            return 0;
        }
    }
    return 0;
}
